+@page "/track"
+@page "/track/{TrackingNumber}"
+@inject IShipmentService ShipmentService
+
+<PageTitle>Track Shipment</PageTitle>
+
+<h1>Track Your Shipment</h1>
+
+<div class="row mb-4">
+    <div class="col-md-6">
+        <div class="input-group">
+            <input type="text" class="form-control" placeholder="Enter tracking number (e.g., TRK-10001)"
+                   @bind="searchTracking" @bind:event="oninput" @onkeydown="HandleKeyDown" />
+            <button class="btn btn-primary" @onclick="SearchShipment" disabled="@isLoading">
+                @if (isLoading)
+                {
+                    <span class="spinner-border spinner-border-sm me-1"></span>
+                }
+                Search
+            </button>
+        </div>
+    </div>
+</div>
+
+@if (errorMessage is not null)
+{
+    <div class="alert alert-warning">@errorMessage</div>
+}
+
+@if (shipment is not null)
+{
+    <div class="card">
+        <div class="card-header d-flex justify-content-between align-items-center">
+            <strong>@shipment.TrackingNumber</strong>
+            <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
+        </div>
+        <div class="card-body">
+            <div class="row">
+                <div class="col-md-6">
+                    <p><strong>Description:</strong> @shipment.Description</p>
+                    <p><strong>Origin:</strong> @shipment.Origin</p>
+                    <p><strong>Destination:</strong> @shipment.Destination</p>
+                </div>
+                <div class="col-md-6">
+                    <p><strong>Shipped:</strong> @shipment.ShippedDate.ToString("MMM dd, yyyy")</p>
+                    <p><strong>Estimated Delivery:</strong> @shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</p>
+                    @if (shipment.Status == ShipmentStatus.Delivered)
+                    {
+                        <p class="text-success fw-bold">✓ Delivered</p>
+                    }
+                    else if (shipment.Status == ShipmentStatus.Delayed)
+                    {
+                        <p class="text-danger fw-bold">⚠ Shipment is delayed</p>
+                    }
+                </div>
+            </div>
+        </div>
+    </div>
+}
+
+@code {
+    [Parameter] public string? TrackingNumber { get; set; }
+
+    private string searchTracking = string.Empty;
+    private Shipment? shipment;
+    private string? errorMessage;
+    private bool isLoading;
+
+    protected override async Task OnParametersSetAsync()
+    {
+        if (!string.IsNullOrWhiteSpace(TrackingNumber))
+        {
+            searchTracking = TrackingNumber;
+            await SearchShipment();
+        }
+    }
+
+    private async Task HandleKeyDown(KeyboardEventArgs e)
+    {
+        if (e.Key == "Enter")
+        {
+            await SearchShipment();
+        }
+    }
+
+    private async Task SearchShipment()
+    {
+        if (string.IsNullOrWhiteSpace(searchTracking)) return;
+
+        isLoading = true;
+        errorMessage = null;
+        shipment = null;
+
+        try
+        {
+            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(searchTracking.Trim());
+            if (shipment is null)
+            {
+                errorMessage = $"No shipment found with tracking number '{searchTracking}'.";
+            }
+        }
+        catch
+        {
+            errorMessage = "Unable to look up shipment. Please try again.";
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
+    {
+        ShipmentStatus.Pending => "bg-secondary",
+        ShipmentStatus.PickedUp => "bg-info",
+        ShipmentStatus.InTransit => "bg-primary",
+        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
+        ShipmentStatus.Delivered => "bg-success",
+        ShipmentStatus.Delayed => "bg-danger",
+        _ => "bg-secondary"
+    };
+}
+

