+@page "/shipments"
+@attribute [Microsoft.AspNetCore.Authorization.Authorize]
+@inject IShipmentService ShipmentService
+
+<PageTitle>Dispatcher Dashboard</PageTitle>
+
+<h1>Dispatcher Dashboard</h1>
+<p>Manage all shipments — filter by status and update as needed.</p>
+
+<div class="row mb-3">
+    <div class="col-md-4">
+        <select class="form-select" @bind="statusFilter">
+            <option value="">All Statuses</option>
+            @foreach (var status in Enum.GetValues<ShipmentStatus>())
+            {
+                <option value="@status">@status</option>
+            }
+        </select>
+    </div>
+    <div class="col-md-4">
+        <input type="text" class="form-control" placeholder="Search destination..."
+               @bind="destinationFilter" @bind:event="oninput" />
+    </div>
+    <div class="col-md-4">
+        <button class="btn btn-outline-primary" @onclick="LoadShipments" disabled="@isLoading">
+            @if (isLoading)
+            {
+                <span class="spinner-border spinner-border-sm me-1"></span>
+            }
+            Refresh
+        </button>
+    </div>
+</div>
+
+@if (shipments is null)
+{
+    <p><em>Loading shipments...</em></p>
+}
+else if (!FilteredShipments.Any())
+{
+    <div class="alert alert-info">No shipments match the current filters.</div>
+}
+else
+{
+    <div class="table-responsive">
+        <table class="table table-striped table-hover">
+            <thead class="table-dark">
+                <tr>
+                    <th>Tracking #</th>
+                    <th>Description</th>
+                    <th>Origin</th>
+                    <th>Destination</th>
+                    <th>Status</th>
+                    <th>Est. Delivery</th>
+                    <th>Action</th>
+                </tr>
+            </thead>
+            <tbody>
+                @foreach (var s in FilteredShipments)
+                {
+                    <tr>
+                        <td><code>@s.TrackingNumber</code></td>
+                        <td>@s.Description</td>
+                        <td>@s.Origin</td>
+                        <td>@s.Destination</td>
+                        <td><span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span></td>
+                        <td>@s.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
+                        <td>
+                            <select class="form-select form-select-sm" value="@s.Status"
+                                    @onchange="(e) => UpdateStatus(s, e)">
+                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
+                                {
+                                    <option value="@status">@status</option>
+                                }
+                            </select>
+                        </td>
+                    </tr>
+                }
+            </tbody>
+        </table>
+    </div>
+}
+
+@code {
+    private List<Shipment>? shipments;
+    private string statusFilter = string.Empty;
+    private string destinationFilter = string.Empty;
+    private bool isLoading;
+
+    private IEnumerable<Shipment> FilteredShipments => (shipments ?? [])
+        .Where(s => string.IsNullOrEmpty(statusFilter) || s.Status.ToString() == statusFilter)
+        .Where(s => string.IsNullOrEmpty(destinationFilter) ||
+                    s.Destination.Contains(destinationFilter, StringComparison.OrdinalIgnoreCase));
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadShipments();
+    }
+
+    private async Task LoadShipments()
+    {
+        isLoading = true;
+        try
+        {
+            shipments = await ShipmentService.GetAllShipmentsAsync();
+        }
+        catch
+        {
+            shipments = [];
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
+    {
+        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
+        {
+            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
+            shipment.Status = newStatus;
+        }
+    }
+
+    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
+    {
+        ShipmentStatus.Pending => "bg-secondary",
+        ShipmentStatus.PickedUp => "bg-info",
+        ShipmentStatus.InTransit => "bg-primary",
+        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
+        ShipmentStatus.Delivered => "bg-success",
+        ShipmentStatus.Delayed => "bg-danger",
+        _ => "bg-secondary"
+    };
+}
+

